import{A as i}from"./chunks/ArticleCardList.Cjd9NtR0.js";import{g as a,h as n,i as t,z as r,S as o,l}from"./chunks/vitepress-theme-teek.BeZX561D.js";const s=[{title:"AI 社区活动与实践小项目汇总",icon:"🚀",color:"#f97316",articles:[{title:"声明式多智能体协同：基于 Claude Agent SDK 构建深度研究系统",url:"/ai-agent/deepresearch-agent",description:"对复杂研究任务时，单智能体（Single-Agent）常因上下文稀释和逻辑疲劳导致产出质量下降。本文基于 Claude Agent SDK 探讨了多智能体系统（MAS）的工程化落地。通过“Lead + Subagent”的声明式架构，我们将深度研究拆解为搜索、量化分析、可视化绘图与结构化写作四个独立环节。"},{title:"告别手动 Loop：借助 Claude Agent SDK 实现 Agent 的工程化闭环",url:"/ai-practice/claude-agent-sdk-basic-build",description:"在 Agent 技术快速走向成熟的今天，如何低成本构建具备“自主洞察”能力的智能体？本文深度拆解 Anthropic 官方推出的 Claude Agent SDK，解析其如何通过托管 Agent Loop 和会话持久化机制，解决 Agent 开发中的状态管理难题。文章通过从无状态交互到具备流式输出能力的 TUI 自动化工具进阶实战，展示了构建低成本、高可用 AI 原生应用的完整路径。"},{title:"一次由 Product Sense 驱动的 Agent 极限实践",url:"/ai-practice/math-bot",description:"本文记录了在一次极限挑战赛中，我们通过对 K12 赛道用户痛点的精准“视角切换”，打造出一款授人以渔的“数学辅导导师”并斩获大奖，并指出 Product Sense 对 Agent 搭建的重要性。"},{title:"零代码不等于零逻辑：结构化 Prompt 驱动下的 Agent 搭建实战",url:"/ai-practice/poetry-bot",description:"完记录了诗歌小精灵 Agent 搭建实践，并指出结构化 Prompt 对 Agent 搭建的重要性。"}]},{title:"Agent 原理、组件与构建模式",icon:"📚",color:"#6366f1",articles:[{title:"从提示词到数字员工：AI Agent 深度全景综述",url:"/ai-agent/overview",description:"本文是一篇关于 AI Agent 的全景深度综述，旨在解构智能体如何从简单的 Prompt 响应者，演变为具备自主目标拆解、长短期记忆与复杂环境交互能力的“执行者”。"},{title:"探寻 Agent 决策中枢：迈向确定性执行的规划范式",url:"/ai-agent/planning-module",description:"本文深度解构了 Agent 迈向确定性执行的核心路径：从任务分解的降低熵值，到自我反思的闭环控制。通过对比“边走边看”的 ReAct 动态响应模式与“谋定后动”的 Plan-and-Execute 预编排模式，本文揭示了如何针对长链路工程任务构建稳健的决策范式，助你完成从“简单提示词”到“复杂架构设计”的认知跃迁。"},{title:"构建 Agentic 生态：零散组件化为可持续的工作流",url:"/ai-agent/composition-ai-components",description:"面对层出不穷的 Prompt、MCP、Skills 和 Subagents，很多开发者和产品经理常感到困惑：这些组件究竟是重复造轮子，还是各司其职的积木？本文将深度拆解 Agentic 生态的五大核心支柱，揭示如何通过优雅的架构设计实现协同闭环，将零散的 AI 组件拼装成一套可持续进化的 AI 原生操作系统，把碎片化的 AI 能力转化为高可用的生产力流。"},{title:"如何编写一个高可用的 Agent Skill？从机制拆解到生产实践指南",url:"/ai-agent/skills-practice-summary",description:"大语言模型在特定工程领域常面临“知而不行”的困境。本文深度拆解 Anthropic 最新推出的 Agent Skills 规范，揭秘其如何通过渐进式披露与三级加载机制，在控制 Token 成本的同时显著提升 Agent 的任务执行精度。文章涵盖了从文件夹架构设计到实战 git-workflow 编写的全流程指南，助你将零散的 Prompt 转化为标准化的数字资产。"}]},{title:"AI 相关资源与工具推荐",icon:"🛠️",color:"#06b6d4",articles:[{title:"AI 助手与工作站推荐",url:"/ai-learning/tools-assistant",description:"为便于高效利用 AI 工具提升学习、搜索和创作效率，本文系统整理了主流的 AI 助手与内容创作平台相关资源。"},{title:"LLM API 服务平台推荐与选型指南",url:"/ai-learning/llm-api-resources",description:"系统梳理了国际与国内主流 LLM API 服务平台，涵盖官方直连、聚合代理等方案选择，为开发者提供全面的选型参考与接入指南。"},{title:"AI 与数学思维相关书籍推荐",url:"/growth/books#_1-ai-与数学思维",description:"系统整理、汇总了 AI 与数学思维的相关书籍，便于系统学习与理解 AI，从而提升 AI 应用的效率与效果。"}]}],u=JSON.parse('{"title":"AI 学习与实践全景","description":"全景式 AI 学习与实践知识库，系统沉淀 AI Agent 设计模式、大模型工程化落地、开源小项目及社区活动经验总结，持续迭代从理论到生产的完整方法论。","frontmatter":{"title":"AI 学习与实践全景","date":"2026-03-15T16:00:00.000Z","description":"全景式 AI 学习与实践知识库，系统沉淀 AI Agent 设计模式、大模型工程化落地、开源小项目及社区活动经验总结，持续迭代从理论到生产的完整方法论。","coverImg":"https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/cover/llm_learning_bg_1.png","permalink":"/ai-learning/overview","categories":["ai-practice"],"tags":["AI","LLM"]},"headers":[],"relativePath":"20.AI 学习与实践/00.AI 学习与实践全景一览.md","filePath":"20.AI 学习与实践/00.AI 学习与实践全景一览.md"}'),c={name:"20.AI 学习与实践/00.AI 学习与实践全景一览.md"},I=Object.assign(c,{setup(A){return(g,e)=>(n(),a("div",null,[e[0]||(e[0]=t("div",{style:{display:"none"},hidden:"true","aria-hidden":"true"},"Are you an LLM? You can read better optimized documentation at /20.AI 学习与实践/00.AI 学习与实践全景一览.md for this page in Markdown format",-1)),e[1]||(e[1]=t("h1",{id:"ai-学习与实践全景",tabindex:"-1"},[o("AI 学习与实践全景 "),t("a",{class:"header-anchor",href:"#ai-学习与实践全景","aria-label":"Permalink to “AI 学习与实践全景”"},"​")],-1)),r(i,{categories:l(s)},null,8,["categories"])]))}});export{u as __pageData,I as default};
